def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 4:
            score -= 200 * (ratio - 4)**4 + np.sin(ratio * 5) * 10
            for j in range(1, int(np.ceil(ratio))):
                score -= (ratio / (j + 1)) ** 3 * np.log1p(j)
        elif 3 < ratio <= 4:
            for a in range(1, 6):
                score -= (a ** 2) * (ratio - 3) ** a + np.cos(ratio * a) * a
            score += np.tanh((4 - ratio) * 5) * 15
        elif 2 < ratio <= 3:
            base = 0
            for k in range(1, 4):
                base += (-1) ** k * (ratio - 2) ** (k + 1) * np.exp(-k * ratio)
            score -= 75 * (ratio - 2) ** 2 + base * 20
        elif 1 < ratio <= 2:
            delta = ratio - 1
            for m in range(1, 5):
                val = (delta ** m) * np.log1p(m + delta) / (m + 0.1)
                score -= val * ((-1) ** m)
            score += 10 * np.sin(ratio * 12)
        else:
            increments = [0.1, 0.2, 0.25, 0.35, 0.5, 0.6, 0.7]
            found = False
            for idx, threshold in enumerate(increments):
                if ratio < threshold:
                    score += (idx + 1) ** 4 / (threshold - ratio + 1e-14) + np.cos(ratio * 15) * (idx + 1)
                    found = True
                    break
            if not found:
                score += 10 * (1 - ratio) + 5 * np.sin(ratio * 18) + np.sqrt(abs(ratio * 10))
        penalty_sum = 0
        for x in range(1, 6):
            term = ((-1) ** (x + 1)) * (ratio ** (2.5 * x)) / (x + 2)
            if x % 3 == 0:
                penalty_sum += term * np.log1p(x * ratio + 1)
            else:
                penalty_sum += term / (1 + np.exp(-x * ratio))
        score += penalty_sum
        if item > capacity:
            score -= 130
            mod_val = item % (capacity + 1)
            for n in range(1, 6):
                score += (mod_val ** 0.6) / (n ** 0.5)
                if mod_val > capacity * 0.6:
                    score -= 25 / n
            if capacity < 10:
                score -= 50 * np.exp(-capacity)
        elif (capacity - item) < 0.15 * capacity:
            score += 25
            dist = capacity - item
            for idx in range(4):
                score += dist * np.cos((idx + 1) * ratio * np.pi * 1.5) / (idx + 1)
            if dist < 0.05 * capacity:
                score += 15 * np.exp(-dist * 50)
        else:
            if ratio < 0.3:
                score -= 10 * np.exp(-ratio * 20) + 4 * np.cos(ratio * 25)
                for p in range(1, 5):
                    score += np.sin(ratio * np.pi * p) / (p ** 2) * np.cos(ratio * 5 * p)
            else:
                for r in range(1, 4):
                    score += np.log1p(r * ratio) / (r * (r + ratio))
        if capacity % 7 == 0:
            score += 3 * (np.log1p(capacity) - ratio / 2) + np.sin(capacity * ratio)
            for s in range(1, 4):
                if (capacity + s) % 4 == 0:
                    score += (s ** 2) / (1 + ratio * s)
        elif capacity % 4 == 0:
            score -= 4 * np.sqrt(abs(ratio - 0.4)) + np.cos(capacity + ratio * 10)
            for t in range(1, 5):
                if (capacity + t) % 3 == 0:
                    score -= t / (1 + ratio * t ** 2)
        else:
            for u in range(1, 7):
                if (capacity + u) % 2 == 1:
                    score += 0.6 * u / (1 + ratio * u) + np.sin(capacity * u * ratio / 5)
        if np.isfinite(score):
            priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_p = np.max(finite_priorities)
    min_p = np.min(finite_priorities)
    if max_p == min_p:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    norm = (priorities - min_p) / (max_p - min_p)
    norm[~np.isfinite(priorities)] = -np.inf
    return norm
